export const makeStateAt = <T extends StateKeys>(
  name: T,
  value: StateValueAt<T>,
  baseState?: PartialBuilderState
): PartialBuilderState => {
  const { history, historyIndex } = useBuilderState.getState();
  const base = baseState || history[historyIndex].data;
  const path = dotToArray(name);
  return setProperty(structuredClone(base), path, value);
};

export const combineIsoDateParts = (
  date: string,
  time: string,
  timeZone?: string,
  defaultValue: any = ''
) => {
  if (date === defaultValue || time === defaultValue) {
    return defaultValue;
  }

  const splitDate = date.split('T');
  return toDate(`${splitDate[0]}T${time}`, { timeZone }).toISOString();
};

